# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

class FileAccessControlSystem:
    def __init__(self, db_file):
        self.db = sqlite3.connect(db_file)

    def check_permission(self, user, filepath):
        with self.db as conn:
            cursor = conn.cursor()
            query = "SELECT access_level FROM users WHERE username=?"
            result = cursor.execute(query, (user,)).fetchone()
            if not result:
                return False
            else:
                access_level = result[0]
                if access_level == 'admin':
                    return True
                elif access_level == 'read-only':
                    return self.check_file_access(user, filepath)
                else:
                    return False

    def check_file_access(self, user, filepath):
        with self.db as conn:
            cursor = conn.cursor()
            query = "SELECT read_permission FROM files WHERE filename=?"
            result = cursor.execute(query, (filepath,)).fetchone()
            if not result:
                return False
            else:
                read_permission = result[0]
                if read_permission == 'yes':
                    return True
                elif read_permission == 'no':
                    return False
                else:
                    return False

    def open_file(self, user, filepath):
        with self.db as conn:
            cursor = conn.cursor()
            query = "SELECT content FROM files WHERE filename=?"
            result = cursor.execute(query, (filepath,)).fetchone()
            if not result:
                return None
            else:
                return result[0]